chrome.runtime.onInstalled.addListener(()=>{console.log("[ชัวร์ก่อนแชร์] Extension installed")});chrome.runtime.onMessage.addListener((e,r,t)=>{if(e.type==="PICKED_TEXT"){const o={sbs_pendingPickedText:e.text};return e.imageUrl&&(o.sbs_pendingPickedImageUrl=e.imageUrl),chrome.storage.local.set(o,()=>{chrome.action.setBadgeText({text:"✓"}),chrome.action.setBadgeBackgroundColor({color:"#059669"}),chrome.action.openPopup().catch(()=>{}),t({ok:!0})}),!0}if(e.type==="OPEN_POPUP_WITH_RESULT")return chrome.storage.local.set({sbs_pendingResultId:e.resultId},()=>{chrome.action.openPopup().catch(()=>{}),t({ok:!0})}),!0});
